import{i as s}from"./theme-C-Ch8ZGE.js";s();localStorage.getItem("token")&&(window.location.href="/dashboard/");const i=document.getElementById("login-form"),e=document.getElementById("error");i.addEventListener("submit",async n=>{n.preventDefault();const a=document.getElementById("username").value.trim(),r=document.getElementById("password").value;e.style.display="none";const t=await fetch("/api/auth/login",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({username:a,password:r})});if(!t.ok){e.textContent="Invalid username or password.",e.style.display="block";return}const o=await t.json();localStorage.setItem("token",o.token),localStorage.setItem("user",JSON.stringify(o.user)),window.location.href="/dashboard/"});
